let totalApplied = 0;
for (const [filename, trans] of Object.entries(translations)) {
  const filePath = path.join(deDir, filename);
  if (!fs.existsSync(filePath)) {
    console.log('SKIP: ' + filename + ' does not exist');
    continue;
  }
  const de = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  let applied = 0;
  for (const [keyPath, value] of Object.entries(trans)) {
    const current = getNested(de, keyPath);
    if (current !== undefined) {
      setNested(de, keyPath, value);
      applied++;
    } else {
      console.log('WARNING: Key "' + keyPath + '" not found in ' + filename);
    }
  }
  fs.writeFileSync(filePath, JSON.stringify(de, null, 2) + '\n', 'utf8');
  console.log(filename + ': ' + applied + ' translations applied');
  totalApplied += applied;
}
console.log('\nTotal translations applied: ' + totalApplied);
